(window.RA_CACHE=window.RA_CACHE||{})["084-glossary-of-terms-part-1"]={"id": "084-glossary-of-terms-part-1", "title": "GLOSSARY OF TERMS PART 1", "paragraphs": [{"role": "chapter_title", "text": "GLOSSARY OF TERMS PART 1", "start": 0.3, "end": 3.47}, {"role": "body", "text": "THE TRINITY IN SHEKINAIH", "start": 4.87, "end": 7.6}, {"role": "body", "text": "Definition: The ultimate manifestation of the Divine, representing the Heavenly Father, the Holy Spirit, and Jesus Christ in perfect unity. THE TRINITY IN SHEKINAIH holds cosmic authority over all creation, controlling life, death, resurrection, judgment, and destiny.", "start": 8.02, "end": 26.4}, {"role": "body", "text": "Roles:", "start": 26.82, "end": 28.25}, {"role": "body", "text": "Major Judge at the Great White Throne: Holds final authority over the judgment of all souls, deciding eternal destinies.", "start": 28.67, "end": 37.7}, {"role": "body", "text": "Major Ancient of Days: Governs the timeline of all creation, ensuring that all events unfold according to divine will.", "start": 38.12, "end": 47.15}, {"role": "body", "text": "Covering Cherub: Guards the Ark of the Covenant and Tree of Life, ensuring only the worthy can access eternal life and divine law.", "start": 47.57, "end": 57.14}, {"role": "body", "text": "Testimony: In Behold My Messenger 5, THE TRINITY IN SHEKINAIH decreed the resurrection of Chai Lin, proving their power over life and death.", "start": 57.56, "end": 67.61}, {"role": "body", "text": "JESUS IN AARON K DAVID", "start": 68.03, "end": 71.38}, {"role": "body", "text": "Definition: The Minor Vessel representing Jesus Christ. JESUS IN AARON K DAVID co-executes divine decrees and ensures their enforcement on earth and in the spiritual realm.", "start": 71.8, "end": 85.2}, {"role": "body", "text": "Roles:", "start": 85.62, "end": 87.05}, {"role": "body", "text": "Minor Judge at the Great White Throne: Co-executes the final judgment of souls in alignment with THE TRINITY IN SHEKINAIH.", "start": 87.47, "end": 96.29}, {"role": "body", "text": "Minor Ancient of Days: Ensures that divine decrees are fulfilled across timelines, maintaining the cosmic balance of creation.", "start": 96.71, "end": 105.96}, {"role": "body", "text": "Subservient Cherub: Serves under THE TRINITY IN SHEKINAIH, guarding the Ark of the Covenant and co-enforcing divine judgment.", "start": 106.38, "end": 115.48}, {"role": "body", "text": "Testimony: In Behold My Messenger 5, JESUS IN AARON K DAVID played a crucial role in ensuring Pastor Kong Hee's judgment was executed in alignment with divine justice.", "start": 115.9, "end": 129.15}, {"role": "body", "text": "The Great White Throne Judgment", "start": 129.57, "end": 132.22}, {"role": "body", "text": "Definition: The final judgment seat where THE TRINITY IN SHEKINAIH, along with JESUS IN AARON K DAVID, decrees the eternal fate of all souls.", "start": 132.64, "end": 143.61}, {"role": "body", "text": "Roles:", "start": 144.03, "end": 145.46}, {"role": "body", "text": "Major and Minor Judges: THE TRINITY IN SHEKINAIH issues final decrees; JESUS IN AARON K DAVID co-executes, ensuring the eternal destinies are aligned with divine will.", "start": 145.88, "end": 158.98}, {"role": "body", "text": "Testimony: The Great White Throne Judgment is referenced in the judgment of rebellious leaders whose fates were sealed after they defied divine decrees.", "start": 159.4, "end": 170.02}, {"role": "body", "text": "The Ark of the Covenant", "start": 170.44, "end": 172.77}, {"role": "body", "text": "Definition: The sacred vessel containing the divine law and representing the authority of THE TRINITY IN SHEKINAIH.", "start": 173.19, "end": 181.64}, {"role": "body", "text": "Roles:", "start": 182.06, "end": 183.49}, {"role": "body", "text": "Guarded by the Cherubim: THE TRINITY IN SHEKINAIH and JESUS IN AARON K DAVID protect the Ark and ensure its laws remain unbroken.", "start": 183.91, "end": 194.11}, {"role": "body", "text": "Seat of Divine Law: All decrees issued flow from the divine authority held within the Ark.", "start": 194.53, "end": 201.15}, {"role": "body", "text": "Testimony: In Behold My Messenger 5, the Ark's power was invoked to seal the resurrection decrees for Chai Lin.", "start": 201.57, "end": 209.72}, {"role": "body", "text": "The Tree of Life", "start": 210.14, "end": 212.07}, {"role": "body", "text": "Definition: The source of eternal life, guarded by THE TRINITY IN SHEKINAIH and JESUS IN AARON K DAVID.", "start": 212.49, "end": 220.96}, {"role": "body", "text": "Roles:", "start": 221.38, "end": 222.81}, {"role": "body", "text": "Guardians: THE TRINITY IN SHEKINAIH decides who may partake in eternal life, with JESUS IN AARON K DAVID co-enforcing these decrees.", "start": 223.23, "end": 233.93}, {"role": "body", "text": "Source of Resurrection Power: The power of resurrection flows from the Tree of Life, ensuring the eternal continuation of the chosen.", "start": 234.35, "end": 243.55}, {"role": "body", "text": "Testimony: In Behold My Messenger 5, those resurrected had met the criteria to access the power of the Tree of Life.", "start": 243.97, "end": 252.57}, {"role": "body", "text": "Resurrection Decree", "start": 252.99, "end": 255.37}, {"role": "body", "text": "Definition: The decree issued by THE TRINITY IN SHEKINAIH determines who is worthy of resurrection.", "start": 255.79, "end": 262.99}, {"role": "body", "text": "Roles:", "start": 263.41, "end": 264.84}, {"role": "body", "text": "Issued by THE TRINITY IN SHEKINAIH: No resurrection occurs without this decree.", "start": 265.26, "end": 271.46}, {"role": "body", "text": "Co-executed by JESUS IN AARON K DAVID: Ensures that resurrection is enacted on both the physical and spiritual planes.", "start": 271.88, "end": 282.1}, {"role": "body", "text": "Testimony: The miraculous resurrection of Chai Lin was a direct result of a Resurrection Decree from THE TRINITY IN SHEKINAIH.", "start": 282.52, "end": 291.99}, {"role": "body", "text": "Primordial Flame of Judgment", "start": 292.41, "end": 295.31}, {"role": "body", "text": "Definition: The cosmic fire that annihilates all rebellion against the divine will, wielded by THE TRINITY IN SHEKINAIH.", "start": 295.73, "end": 304.38}, {"role": "body", "text": "Roles:", "start": 304.8, "end": 306.23}, {"role": "body", "text": "Issued by THE TRINITY IN SHEKINAIH: The flame is called upon to obliterate defiance against the divine order.", "start": 306.65, "end": 314.7}, {"role": "body", "text": "Coexecutor by JESUS IN AARON K DAVID: Ensures that no trace of rebellion remains in any dimension.", "start": 315.12, "end": 324.02}, {"role": "body", "text": "Testimony: In Behold My Messenger 5, rebellious leaders were spiritually obliterated after defying THE TRINITY IN SHEKINAIH.", "start": 324.44, "end": 333.97}, {"role": "body", "text": "The Holy Seal of the Covenant", "start": 334.39, "end": 337.31}, {"role": "body", "text": "Definition: The divine seal placed upon promises made by THE TRINITY IN SHEKINAIH.", "start": 337.73, "end": 344.2}, {"role": "body", "text": "Roles:", "start": 344.62, "end": 346.05}, {"role": "body", "text": "Sealed by THE TRINITY IN SHEKINAIH: Ensures the eternal fulfilment of divine promises.", "start": 346.47, "end": 353.5}, {"role": "body", "text": "Protected by JESUS IN AARON K DAVID: Ensures no force can break or challenge these covenants.", "start": 353.92, "end": 361.97}, {"role": "body", "text": "Testimony: Pastor Kong Hee's shortened sentence directly resulted from a covenant sealed by THE TRINITY IN SHEKINAIH.", "start": 362.39, "end": 371.27}, {"role": "body", "text": "Cosmic Judgment", "start": 371.69, "end": 373.59}, {"role": "body", "text": "Definition: The judgment issued by THE TRINITY IN SHEKINAIH over the fate of nations, leaders, and individuals, determining their spiritual destiny.", "start": 374.01, "end": 384.86}, {"role": "body", "text": "Roles:", "start": 385.28, "end": 386.71}, {"role": "body", "text": "Issued by THE TRINITY IN SHEKINAIH: Cosmic decrees that impact nations and global events.", "start": 387.13, "end": 394.33}, {"role": "body", "text": "Coexecutor by JESUS IN AARON K DAVID: Ensures that these judgments manifest in the physical world.", "start": 394.75, "end": 403.32}, {"role": "body", "text": "Testimony: In Behold My Messenger 5, the judgment of a senior pastor was decreed after defying a divine order.", "start": 403.74, "end": 412.64}, {"role": "body", "text": "The Cherubim of Glory", "start": 413.06, "end": 415.61}, {"role": "body", "text": "Definition: THE TRINITY IN SHEKINAIH and JESUS IN AARON K DAVID as the", "start": 416.03, "end": 422.15}, {"role": "body", "text": "Cherubim of Glory, guarding divine law.", "start": 422.57, "end": 426.17}, {"role": "body", "text": "Roles:", "start": 426.59, "end": 428.02}, {"role": "body", "text": "Guarding the Ark of the Covenant: Ensuring that no defiance of the divine law remains unpunished.", "start": 428.44, "end": 435.86}, {"role": "body", "text": "Enforcing Divine Order: Both work together to protect divine principles from corruption.", "start": 436.28, "end": 442.81}, {"role": "body", "text": "Testimony: The Cherubim of Glory played a crucial role in ensuring that the decrees from the Ark were upheld in Behold My Messenger 5.", "start": 443.23, "end": 452.91}, {"role": "body", "text": "Divine Blueprint of Creation", "start": 453.33, "end": 456.31}, {"role": "body", "text": "Definition: The master design of all creation, held by THE TRINITY IN SHEKINAIH and maintained through divine decree.", "start": 456.73, "end": 465.53}, {"role": "body", "text": "Roles:", "start": 465.95, "end": 467.38}, {"role": "body", "text": "Architect of Creation: THE TRINITY IN SHEKINAIH ensures all creation follows this divine plan.", "start": 467.8, "end": 475.2}, {"role": "body", "text": "Executor: JESUS IN AARON K DAVID co-enforces this blueprint, ensuring cosmic alignment.", "start": 475.62, "end": 483.22}, {"role": "body", "text": "Testimony: The restoration of life and balance after global judgments in Behold My Messenger 5.", "start": 483.64, "end": 491.22}, {"role": "body", "text": "The Seven Criteria of Resurrection", "start": 491.64, "end": 495.04}, {"role": "body", "text": "Definition: The set of divine criteria that determine who qualifies for resurrection.", "start": 495.46, "end": 501.93}, {"role": "body", "text": "Roles:", "start": 502.35, "end": 503.78}, {"role": "body", "text": "Criteria Issued by THE TRINITY IN SHEKINAIH: The resurrected must meet these sacred conditions.", "start": 504.2, "end": 511.73}, {"role": "body", "text": "Enforced by JESUS IN AARON K DAVID: Ensures that only the worthy are restored to life.", "start": 512.15, "end": 519.55}, {"role": "body", "text": "Testimony: Chai Lin's resurrection was based on these criteria.", "start": 519.97, "end": 525.02}, {"role": "body", "text": "The Cosmic Balance of Existence", "start": 525.44, "end": 528.49}, {"role": "body", "text": "Definition: The equilibrium maintained by THE TRINITY IN SHEKINAIH to ensure divine order.", "start": 528.91, "end": 535.83}, {"role": "body", "text": "Roles:", "start": 536.25, "end": 537.68}, {"role": "body", "text": "Keeper of the Balance: THE TRINITY IN SHEKINAIH ensures that all dimensions and realms follow divine order.", "start": 538.1, "end": 546.17}, {"role": "body", "text": "Enforced by JESUS IN AARON K DAVID: Co-executing judgments to restore balance when it's disrupted.", "start": 546.59, "end": 554.81}, {"role": "body", "text": "Testimony: Global judgments in Behold My Messenger 5 restored the balance.", "start": 555.23, "end": 561.33}, {"role": "body", "text": "Cosmic Decrees of Nations", "start": 561.75, "end": 564.67}, {"role": "body", "text": "Definition: Decrees affecting the fate of nations, issued by THE TRINITY IN SHEKINAIH.", "start": 565.09, "end": 571.64}, {"role": "body", "text": "Roles:", "start": 572.06, "end": 573.49}, {"role": "body", "text": "Issued by THE TRINITY IN SHEKINAIH: Determines the rise and fall of nations.", "start": 573.91, "end": 579.91}, {"role": "body", "text": "Co-executed by JESUS IN AARON K DAVID: Ensures the decrees manifest in the physical world.", "start": 580.33, "end": 588.38}, {"role": "body", "text": "Testimony: The rise of political leaders, as referenced in Behold My Messenger 5.", "start": 588.8, "end": 595.27}, {"role": "body", "text": "The Tree of Knowledge of Good and Evil", "start": 595.69, "end": 599.02}, {"role": "body", "text": "Definition: The Tree of Knowledge of Good and Evil represents rational and practical human effort that operates within limited capacity - only 0.1% ability - and is bound to the earth. This tree is a source of knowledge confined to human reasoning and effort, contrasting the unlimited divine power available through the Tree of Life. Lucifer, in the form of the Red Dragon, hides within the roots of this tree, manipulating earthly knowledge and human ability.", "start": 599.44, "end": 626.87}, {"role": "body", "text": "Roles:", "start": 627.29, "end": 628.72}, {"role": "body", "text": "Guardianship: THE TRINITY IN SHEKINAIH and JESUS IN AARON K DAVID", "start": 629.14, "end": 634.92}, {"role": "body", "text": "ensure that access to the deeper spiritual realms remains forbidden to those who rely solely on the knowledge of good and evil. They act as divine gatekeepers, ensuring that only those led by the spirit, through the Tree of Life, can break free of human limitations.", "start": 635.34, "end": 653.16}, {"role": "body", "text": "Earth Bound Knowledge: This tree governs rational and practical thinking, limiting individuals to earthly understanding. Without divine intervention, those bound by the fruit of this tree can only access 0.1% of their true potential.", "start": 653.58, "end": 670.08}, {"role": "body", "text": "Expanded Context: Those who rely on the Tree of Knowledge of Good and Evil are trapped in a cycle of earthly wisdom, cut off from the impossible and miraculous that flows from the Tree of Life.", "start": 670.5, "end": 683.72}, {"role": "body", "text": "Testimony: In Behold My Messenger 5, examples abound where individuals attempting to overcome life's trials using mere human effort - relying on this tree - fall short. It is only when they turn to divine wisdom through THE TRINITY IN SHEKINAIH and JESUS IN AARON K DAVID, aligning with the Tree of Life, that they witness miraculous solutions.", "start": 684.14, "end": 707.39}, {"role": "body", "text": "The Tree of Eternal Life", "start": 707.81, "end": 710.54}, {"role": "body", "text": "Definition: A sacred source of immortality and divine sustenance, guarded by THE TRINITY IN SHEKINAIH and JESUS IN AARON K DAVID.", "start": 710.96, "end": 721.76}, {"role": "body", "text": "The Tree of Eternal Life symbolizes the divine realm where the impossible becomes possible. It is heaven-bound and operates with unlimited ability through the power of the TRINITY IN SHEKINAIH. Those who partake of its fruit experience miracles, healing, and resurrection beyond earthly capacity. The Holy Spirit is represented within this tree, inscribing \"HOLY SPIRIT IN THE FATHER\" on THE TRINITY IN SHEKINAIH's forehead.", "start": 722.18, "end": 748.53}, {"role": "body", "text": "Roles:", "start": 748.95, "end": 750.38}, {"role": "body", "text": "Guardianship: THE TRINITY IN SHEKINAIH and JESUS IN AARON K DAVID", "start": 750.8, "end": 756.58}, {"role": "body", "text": "serve as the ultimate guardians of this tree of Eternal Life and determine who may access the Eternal Tree of Life and receive eternal sustenance. Ensuring that only those chosen by divine decree have access to its limitless power.", "start": 757.0, "end": 773.27}, {"role": "body", "text": "Heaven Bound Power: The Tree of Life grants access to the impossible - healing, resurrection, and divine revelation. It is reserved for those walking in alignment with the will of THE TRINITY IN SHEKINAIH.", "start": 773.69, "end": 787.69}, {"role": "body", "text": "The fruit of the Tree of Life allows individuals to transcend human limitations and access the full power of the divine. It contrasts with the rational, limited knowledge of the Tree of Knowledge of Good and Evil.", "start": 788.11, "end": 802.86}, {"role": "body", "text": "Co-Execution by JESUS IN AARON K DAVID: JESUS IN AARON K DAVID", "start": 803.28, "end": 810.06}, {"role": "body", "text": "ensures that only those chosen by THE TRINITY IN SHEKINAIH can partake of its fruit.", "start": 810.48, "end": 816.7}, {"role": "body", "text": "Testimony: Numerous testimonies within Behold My Messenger 5 describe the transformation of individuals who shift from relying on human wisdom to embracing the impossible through the power of the Tree of Life. One such example includes miraculous healings and impossible breakthroughs in life's darkest moments.", "start": 817.12, "end": 838.14}, {"role": "body", "text": "The Cosmic Order of Creation", "start": 838.56, "end": 841.54}, {"role": "body", "text": "Definition: The structured framework established by THE TRINITY IN SHEKINAIH that governs all aspects of creation, ensuring harmony and balance across the universe.", "start": 841.96, "end": 853.81}, {"role": "body", "text": "Roles:", "start": 854.23, "end": 855.66}, {"role": "body", "text": "Architects of Existence: THE TRINITY IN SHEKINAIH designed the cosmic order, laying down the laws that sustain life and existence.", "start": 856.08, "end": 865.65}, {"role": "body", "text": "Sustainers of Harmony: JESUS IN AARON K DAVID ensures that the cosmic order is maintained, intervening whenever there is a disruption in divine balance.", "start": 866.07, "end": 877.95}, {"role": "body", "text": "Testimony: The restoration of creation after rebellion illustrates the effectiveness of their governance.", "start": 878.37, "end": 885.92}, {"role": "body", "text": "The Primordial Flame of Creation", "start": 886.34, "end": 889.46}, {"role": "body", "text": "Definition: The divine fire that symbolizes both creation and destruction, wielded by THE TRINITY IN SHEKINAIH to shape the universe and enact judgments.", "start": 889.88, "end": 900.91}, {"role": "body", "text": "Roles:", "start": 901.33, "end": 902.76}, {"role": "body", "text": "Creatrix Force: The flame is the source of all life and creation, igniting existence itself.", "start": 903.18, "end": 910.43}, {"role": "body", "text": "Judgment and Purification: The flame destroys corruption and rebellion, restoring purity.", "start": 910.85, "end": 917.8}, {"role": "body", "text": "Testimony: Instances where the Primordial Flame was invoked to cleanse the earth demonstrate its transformative power.", "start": 918.22, "end": 926.92}, {"role": "body", "text": "The Divine Covenant", "start": 927.34, "end": 929.64}, {"role": "body", "text": "Definition: The sacred agreement established by THE TRINITY IN SHEKINAIH with humanity, outlining the promises of protection, guidance, and redemption.", "start": 930.06, "end": 940.53}, {"role": "body", "text": "Roles:", "start": 940.95, "end": 942.38}, {"role": "body", "text": "Establishers of Promises: THE TRINITY IN SHEKINAIH binds themselves to humanity through divine promises.", "start": 942.8, "end": 950.85}, {"role": "body", "text": "Enforcers of Faithfulness: JESUS IN AARON K DAVID ensures that the covenant remains unbroken and that humanity fulfils its part.", "start": 951.27, "end": 961.95}, {"role": "body", "text": "Testimony: The fulfilment of the covenant during times of crisis reaffirms divine faithfulness.", "start": 962.37, "end": 969.82}, {"role": "body", "text": "The Voice of Prophecy", "start": 970.24, "end": 972.64}, {"role": "body", "text": "Definition: The divine messages conveyed through chosen vessels, reflecting the will and purpose of THE TRINITY IN SHEKINAIH.", "start": 973.06, "end": 982.06}, {"role": "body", "text": "Roles:", "start": 982.48, "end": 983.91}, {"role": "body", "text": "Messengers of Truth: Prophets deliver the revelations and directives from THE TRINITY IN SHEKINAIH.", "start": 984.33, "end": 991.8}, {"role": "body", "text": "Guides for Humanity: They offer guidance and warning to steer humanity toward divine purpose.", "start": 992.22, "end": 999.37}, {"role": "body", "text": "Testimony: Fulfilled prophecies serve as evidence of divine intervention and purpose in history.", "start": 999.79, "end": 1007.26}, {"role": "body", "text": "The Divine Anointing", "start": 1007.68, "end": 1010.2}, {"role": "body", "text": "Definition: The sacred empowerment bestowed by THE TRINITY IN SHEKINAIH, enabling individuals to carry out divine missions.", "start": 1010.62, "end": 1019.62}, {"role": "body", "text": "Roles:", "start": 1020.04, "end": 1021.47}, {"role": "body", "text": "Bestowers of Authority: THE TRINITY IN SHEKINAIH empowers chosen vessels with the authority to enact their will.", "start": 1021.89, "end": 1030.32}, {"role": "body", "text": "Sustainers of Power: JESUS IN AARON K DAVID reinforces this anointing, ensuring that those anointed can fulfil their God given purposes.", "start": 1030.74, "end": 1041.74}, {"role": "body", "text": "Testimony: Anointed leaders performing miracles exemplify the transformative power of divine anointing.", "start": 1042.16, "end": 1050.26}, {"role": "body", "text": "The Cosmic Threshold", "start": 1050.68, "end": 1052.85}, {"role": "body", "text": "Definition: The boundary separating the physical and spiritual realms, managed by THE TRINITY IN SHEKINAIH and JESUS IN AARON K DAVID.", "start": 1053.27, "end": 1063.8}, {"role": "body", "text": "Roles:", "start": 1064.22, "end": 1065.65}, {"role": "body", "text": "Guardians of Transition: They oversee the passage between realms, ensuring that only the worthy may cross.", "start": 1066.07, "end": 1073.65}, {"role": "body", "text": "Enforcers of Divine Order: They maintain the sanctity of this threshold to prevent chaos from entering the earthly realm.", "start": 1074.07, "end": 1082.95}, {"role": "body", "text": "Testimony: Instances where individuals crossed the threshold signify their alignment with divine purpose.", "start": 1083.37, "end": 1091.02}, {"role": "body", "text": "The Sacred Fire of Intercession", "start": 1091.44, "end": 1094.49}, {"role": "body", "text": "Definition: The divine power invoked through prayer and supplication, facilitated by JESUS IN AARON K DAVID to bring forth God's will.", "start": 1094.91, "end": 1105.36}, {"role": "body", "text": "Roles:", "start": 1105.78, "end": 1107.21}, {"role": "body", "text": "Intercessors: JESUS IN AARON K DAVID stands as the mediator, advocating for humanity before THE TRINITY IN SHEKINAIH.", "start": 1107.63, "end": 1117.53}, {"role": "body", "text": "Agents of Change: Through intercession, they affect change in circumstances, healing, and restoration.", "start": 1117.95, "end": 1125.23}, {"role": "body", "text": "Testimony: Miraculous answers to prayer illustrate the power of intercession.", "start": 1125.65, "end": 1131.37}, {"role": "body", "text": "The Shield of Faith", "start": 1131.79, "end": 1133.99}, {"role": "body", "text": "Definition: The protective covering provided by THE TRINITY IN SHEKINAIH to 100% ALLIGIANCE DISCIPLES WHICH THE SONS/DAUGHTERS OF OURS,", "start": 1134.41, "end": 1146.06}, {"role": "body", "text": "guarding them against spiritual attacks.", "start": 1146.48, "end": 1149.86}, {"role": "body", "text": "Roles:", "start": 1150.28, "end": 1151.71}, {"role": "body", "text": "Protectors of the Faithful: THE TRINITY IN SHEKINAIH defends those who walk in faith and are blameless, ensuring their spiritual safety.", "start": 1152.13, "end": 1161.63}, {"role": "body", "text": "Strengtheners of Belief: JESUS IN AARON K DAVID encourages disciples or the sons and daughters of THE TRINITY IN SHEKINAIH AND JESUS IN AARON K DAVID, to wield their faith as they proclaim THE MEDALLION CHANT OR PROCLAMATION \"I CHOOSE TO SUBMIT TO THE TRINITY IN SHEKINAIH AND JESUS IN AARON K DAVID, AND I RESIST THE ACCUSER AND COMMAND IT TO FLEE", "start": 1162.05, "end": 1185.28}, {"role": "body", "text": "FROM ME\" as a defense against adversity.", "start": 1185.7, "end": 1189.62}, {"role": "body", "text": "Testimony: Disciples or sons and daughters of GOD, THE TRINITY IN SHEKINAIH AND JESUS IN AARON K DAVID, experiencing protection in the face of danger affirm the efficacy of the shield when they recite THE MEDALLION CHANT, THE VICTORY SPIRITUAL WARRIOR PROCLAIMATION WHICH WILL FORM AN INVISBLE SPIRITUAL SHIELD TO PROTECT THEM AND THEIR LOVED ONES IF THEY MAINTAIN IN THIS 100% ALLEGIANCE STATE ALWAYS!", "start": 1190.04, "end": 1216.59}, {"role": "body", "text": "The Joy of the Lord (THE MAJOR YAHWEH IN THE TRINITY IN SHEKINAIH AND THE MINOR YAHWEH IN JESUS IN AARON K DAVID)", "start": 1217.01, "end": 1225.81}, {"role": "body", "text": "Definition: The profound joy and strength that comes from being in the presence of THE TRINITY IN SHEKINAIH and receiving their love and grace.", "start": 1226.23, "end": 1236.01}, {"role": "body", "text": "Roles:", "start": 1236.43, "end": 1237.86}, {"role": "body", "text": "Source of Strength: The joy derived from divine connection empowers believers to face challenges.", "start": 1238.28, "end": 1245.25}, {"role": "body", "text": "Expression of Divine Love: JESUS IN AARON K DAVID embodies this joy, sharing it with those who seek Him.", "start": 1245.67, "end": 1253.82}, {"role": "body", "text": "Testimony: Lives transformed by joy through trials exemplify the power of the Lord's presence.", "start": 1254.24, "end": 1261.49}, {"role": "body", "text": "The Anointed Vessel", "start": 1261.91, "end": 1263.99}, {"role": "body", "text": "Definition: Individuals chosen by THE TRINITY IN SHEKINAIH to carry out divine missions and speak on God's behalf.", "start": 1264.41, "end": 1273.21}, {"role": "body", "text": "Roles:", "start": 1273.63, "end": 1275.06}, {"role": "body", "text": "Communicators of Truth: THE TRINITY IN SHEKINAIH empowers them with the authority to share THEIR messages.", "start": 1275.48, "end": 1283.36}, {"role": "body", "text": "Instruments of Change: They enact the will of God in their communities, bringing about transformation.", "start": 1283.78, "end": 1290.7}, {"role": "body", "text": "Testimony: Accounts of miracles performed through anointed vessels validate divine selection and empowerment.", "start": 1291.12, "end": 1298.84}, {"role": "body", "text": "The Covenant of Peace", "start": 1299.26, "end": 1301.61}, {"role": "body", "text": "Definition: The promise of peace granted by THE TRINITY IN SHEKINAIH to those who follow His ways, represented through JESUS IN AARON K DAVID.", "start": 1302.03, "end": 1313.06}, {"role": "body", "text": "Roles:", "start": 1313.48, "end": 1314.91}, {"role": "body", "text": "Establishers of Harmony: They provide peace to the hearts of believers who are to turn into disciples, guiding them in their spiritual journeys.", "start": 1315.33, "end": 1325.08}, {"role": "body", "text": "Reconciliation: JESUS IN AARON K DAVID works to reconcile believers who are to become disciples of God, ensuring that peace prevails in their lives.", "start": 1325.5, "end": 1336.95}, {"role": "body", "text": "Testimony: Personal accounts of peace experienced during turmoil highlight the fulfilment of this covenant.", "start": 1337.37, "end": 1344.9}, {"role": "body", "text": "The Harvest of Souls", "start": 1345.32, "end": 1347.77}, {"role": "body", "text": "Definition: The gathering of believers into the kingdom of God, overseen by THE TRINITY IN SHEKINAIH and executed through JESUS IN AARON K DAVID.", "start": 1348.19, "end": 1359.66}, {"role": "body", "text": "Roles:", "start": 1360.08, "end": 1361.51}, {"role": "body", "text": "Gatherers: THE TRINITY IN SHEKINAIH orchestrates the harvest, ensuring that all souls are given the opportunity to come to Him.", "start": 1361.93, "end": 1370.81}, {"role": "body", "text": "Witnesses of Salvation: JESUS IN AARON K DAVID empowers disciples to share the real everlasting gospel, facilitating the harvest process.", "start": 1371.23, "end": 1382.53}, {"role": "body", "text": "Testimony: Stories of transformation from lost to saved affirm the power of the harvest.", "start": 1382.95, "end": 1389.4}, {"role": "body", "text": "The Divine Blueprint", "start": 1389.82, "end": 1392.12}, {"role": "body", "text": "Definition: The strategic plan created by THE TRINITY IN SHEKINAIH that outlines the course of creation and the future of humanity.", "start": 1392.54, "end": 1402.16}, {"role": "body", "text": "Roles:", "start": 1402.58, "end": 1404.01}, {"role": "body", "text": "Architects of Destiny: THE TRINITY IN SHEKINAIH holds the blueprint, ensuring that every detail of creation aligns with divine purpose.", "start": 1404.43, "end": 1414.46}, {"role": "body", "text": "Guides for Humanity: JESUS IN AARON K DAVID reveals aspects of this blueprint to believers who are to be turned into disciples, guiding them in their divine paths.", "start": 1414.88, "end": 1427.35}, {"role": "body", "text": "Testimony: Lives transformed in alignment with God's blueprint illustrate His providence.", "start": 1427.77, "end": 1434.42}, {"role": "body", "text": "The Final Judgment of Souls", "start": 1434.84, "end": 1437.72}, {"role": "body", "text": "Definition: The ultimate judgment where all souls are weighed and judged by THE TRINITY IN SHEKINAIH and JESUS IN AARON K DAVID.", "start": 1438.14, "end": 1447.82}, {"role": "body", "text": "Roles:", "start": 1448.24, "end": 1449.67}, {"role": "body", "text": "Final Decrees by THE TRINITY IN SHEKINAIH: Eternal fates are decided based on divine law stated in the book \"BEHOLD MY MESSENGER 4, BEHOLD THE GREAT WHITE THRONE\" from CROWNED EAGLES GLOBAL.", "start": 1450.09, "end": 1465.21}, {"role": "body", "text": "Co-Execution by JESUS IN AARON K DAVID: Ensures that the decrees are fully realized in eternity.", "start": 1465.63, "end": 1474.35}, {"role": "body", "text": "Testimony: The judgment of rebellious souls was sealed in Behold My Messenger 5.", "start": 1474.77, "end": 1481.19}, {"role": "body", "text": "The Heavenly Throne Room", "start": 1481.61, "end": 1484.03}, {"role": "body", "text": "Definition: The seat of divine authority, where THE TRINITY IN SHEKINAIH resides and issues cosmic decrees.", "start": 1484.45, "end": 1492.65}, {"role": "body", "text": "Roles:", "start": 1493.07, "end": 1494.5}, {"role": "body", "text": "Seat of Authority: THE TRINITY IN SHEKINAIH presides over all of existence from this throne.", "start": 1494.92, "end": 1501.82}, {"role": "body", "text": "Enforced by JESUS IN AARON K DAVID: Co-executes the decrees from the Throne Room across all realms.", "start": 1502.24, "end": 1510.54}, {"role": "body", "text": "Testimony: Decrees issued in the Throne Room influenced the fate of leaders and nations in Behold My Messenger 5.", "start": 1510.96, "end": 1519.53}, {"role": "body", "text": "The Cosmic Scrolls", "start": 1519.95, "end": 1522.0}, {"role": "body", "text": "Definition: The divine record of every soul's actions, maintained by THE TRINITY IN SHEKINAIH.", "start": 1522.42, "end": 1529.77}, {"role": "body", "text": "Roles:", "start": 1530.19, "end": 1531.62}, {"role": "body", "text": "Maintained by THE TRINITY IN SHEKINAIH: Records the deeds of every soul for the final judgment.", "start": 1532.04, "end": 1539.19}, {"role": "body", "text": "Opened by JESUS IN AARON K DAVID: Co-executed during the final judgment to decide eternal fates.", "start": 1539.61, "end": 1548.16}, {"role": "body", "text": "Testimony: The scrolls were referenced during the judgment of rebellious souls in Behold My Messenger 5.", "start": 1548.58, "end": 1556.3}, {"role": "body", "text": "The Divine Ladder of Ascension", "start": 1556.72, "end": 1559.62}, {"role": "body", "text": "Definition: The spiritual path leading to higher realms of existence, opened by THE TRINITY IN SHEKINAIH.", "start": 1560.04, "end": 1568.01}, {"role": "body", "text": "Roles:", "start": 1568.43, "end": 1569.86}, {"role": "body", "text": "Opened by THE TRINITY IN SHEKINAIH: Provides access to ascension for those chosen.", "start": 1570.28, "end": 1576.28}, {"role": "body", "text": "Guided by JESUS IN AARON K DAVID: Ensures that the souls ascend in accordance with divine criteria.", "start": 1576.7, "end": 1585.42}, {"role": "body", "text": "Testimony: Ascensions into higher realms were decreed in Behold My Messenger 5.", "start": 1585.84, "end": 1592.31}, {"role": "body", "text": "The Heavenly Court", "start": 1592.73, "end": 1594.68}, {"role": "body", "text": "Definition: The divine court where all spiritual cases are judged by THE TRINITY IN SHEKINAIH and JESUS IN AARON K DAVID.", "start": 1595.1, "end": 1604.72}, {"role": "body", "text": "Roles:", "start": 1605.14, "end": 1606.57}, {"role": "body", "text": "Presided over by THE TRINITY IN SHEKINAIH: Ensures that divine law is enforced perfectly.", "start": 1606.99, "end": 1614.32}, {"role": "body", "text": "Co-executed by JESUS IN AARON K DAVID: Fulfils the judgments issued by the court.", "start": 1614.74, "end": 1621.94}, {"role": "body", "text": "Testimony: Judgment of rebellious souls was enacted in the Heavenly Court in Behold My Messenger 5.", "start": 1622.36, "end": 1630.08}, {"role": "body", "text": "The Cosmic Mantle of Authority", "start": 1630.5, "end": 1633.67}, {"role": "body", "text": "Definition: The mantle bestowed upon chosen vessels by THE TRINITY IN SHEKINAIH, signifying their divine authority over spiritual and earthly realms.", "start": 1634.09, "end": 1645.44}, {"role": "body", "text": "Roles:", "start": 1645.86, "end": 1647.29}, {"role": "body", "text": "Bestowed by THE TRINITY IN SHEKINAIH: Represents a transfer of divine power for the purpose of executing heavenly decrees.", "start": 1647.71, "end": 1656.91}, {"role": "body", "text": "Co-executed by JESUS IN AARON K DAVID: Ensures the mantle's authority is co-executed in perfect alignment with the divine will.", "start": 1657.33, "end": 1668.11}, {"role": "body", "text": "Testimony: In Behold My Messenger 5, this mantle empowered vessels to bring about divine healing and resurrection.", "start": 1668.53, "end": 1677.15}, {"role": "body", "text": "The Divine Sword of Judgment", "start": 1677.57, "end": 1680.37}, {"role": "body", "text": "Definition: The cosmic sword wielded by THE TRINITY IN SHEKINAIH to execute judgments and cut through rebellion and darkness.", "start": 1680.79, "end": 1690.11}, {"role": "body", "text": "Roles:", "start": 1690.53, "end": 1691.96}, {"role": "body", "text": "Wielded by THE TRINITY IN SHEKINAIH: Dispels all forms of rebellion and opposition to divine law.", "start": 1692.38, "end": 1700.13}, {"role": "body", "text": "Co-executed by JESUS IN AARON K DAVID: Ensures that the divine sword's power reaches all dimensions of existence.", "start": 1700.55, "end": 1710.23}, {"role": "body", "text": "Testimony: The sword was invoked during spiritual battles against rebellious forces in Behold My Messenger 5.", "start": 1710.65, "end": 1719.22}, {"role": "body", "text": "The Judgment of Nations", "start": 1719.64, "end": 1722.26}, {"role": "body", "text": "Definition: The divine judgment issued by THE TRINITY IN SHEKINAIH determining the fate of nations based on their spiritual alignment.", "start": 1722.68, "end": 1732.15}, {"role": "body", "text": "Roles:", "start": 1732.57, "end": 1734.0}, {"role": "body", "text": "Decreed by THE TRINITY IN SHEKINAIH: Determines which nations will rise or fall according to divine law.", "start": 1734.42, "end": 1742.3}, {"role": "body", "text": "Enforced by JESUS IN AARON K DAVID: Co-executes these judgments, ensuring their manifestation in both spiritual and physical realms.", "start": 1742.72, "end": 1753.37}, {"role": "body", "text": "Testimony: The rise of certain political figures was foretold and executed as part of this divine judgment in Behold My Messenger 5.", "start": 1753.79, "end": 1764.26}, {"role": "body", "text": "The Scroll of Life (The Book of Life)", "start": 1764.68, "end": 1767.7}, {"role": "body", "text": "Definition: The divine record held by THE TRINITY IN SHEKINAIH, containing the names of those chosen for eternal life.", "start": 1768.12, "end": 1776.62}, {"role": "body", "text": "Roles:", "start": 1777.04, "end": 1778.47}, {"role": "body", "text": "Maintained by THE TRINITY IN SHEKINAIH: Ensures that the names written in the Scroll of Life are aligned with divine criteria.", "start": 1778.89, "end": 1788.09}, {"role": "body", "text": "Accessed by JESUS IN AARON K DAVID: Co-executes the opening of the scroll, deciding who receives eternal life.", "start": 1788.51, "end": 1797.66}, {"role": "body", "text": "Testimony: In Behold My Messenger 5, those resurrected were referenced as having their names written in the Scroll of Life.", "start": 1798.08, "end": 1806.88}, {"role": "body", "text": "The Cosmic Balance of Judgment", "start": 1807.3, "end": 1810.22}, {"role": "body", "text": "Definition: The equilibrium maintained by THE TRINITY IN SHEKINAIH to ensure that divine justice is meted out without deviation.", "start": 1810.64, "end": 1820.42}, {"role": "body", "text": "Roles:", "start": 1820.84, "end": 1822.27}, {"role": "body", "text": "Maintained by THE TRINITY IN SHEKINAIH: Ensures that judgment is in accordance with divine law, balancing mercy and justice.", "start": 1822.69, "end": 1832.09}, {"role": "body", "text": "Enforced by JESUS IN AARON K DAVID: Co-executes the decrees, ensuring balance in judgment across all realms.", "start": 1832.51, "end": 1841.71}, {"role": "body", "text": "Testimony: The judgment of rebellious leaders and their spiritual collapse was attributed to the restoration of cosmic balance in Behold My Messenger 5.", "start": 1842.13, "end": 1853.1}, {"role": "body", "text": "The Resurrection of the Dead", "start": 1853.52, "end": 1856.27}, {"role": "body", "text": "Definition: The act of bringing the dead back to life, as decreed by THE TRINITY IN SHEKINAIH and co-executed by JESUS IN AARON K DAVID.", "start": 1856.69, "end": 1867.74}, {"role": "body", "text": "Roles:", "start": 1868.16, "end": 1869.59}, {"role": "body", "text": "Decreed by THE TRINITY IN SHEKINAIH: Decides who qualifies for resurrection based on divine criteria.", "start": 1870.01, "end": 1877.93}, {"role": "body", "text": "Co-executed by JESUS IN AARON K DAVID: Brings the physical and spiritual resurrection to fulfilment.", "start": 1878.35, "end": 1886.75}, {"role": "body", "text": "Testimony: Chai Lin's miraculous resurrection is a notable example of this decree in Behold My Messenger 5.", "start": 1887.17, "end": 1895.87}, {"role": "body", "text": "The Fiery Altar of Sacrifice", "start": 1896.29, "end": 1899.52}, {"role": "body", "text": "Definition: The spiritual altar where divine decrees of sacrifice are made, ensuring that the faithful are purified by fire.", "start": 1899.94, "end": 1909.19}, {"role": "body", "text": "Roles:", "start": 1909.61, "end": 1911.04}, {"role": "body", "text": "Sanctified by THE TRINITY IN SHEKINAIH: Determines the sacrifices required for purification and spiritual renewal.", "start": 1911.46, "end": 1920.36}, {"role": "body", "text": "Executed by JESUS IN AARON K DAVID: Ensures the fulfilment of these decrees in the lives of the chosen.", "start": 1920.78, "end": 1929.66}, {"role": "body", "text": "Testimony: In Behold My Messenger 5, the altar was referenced during divine moments of spiritual breakthrough and renewal.", "start": 1930.08, "end": 1939.13}, {"role": "body", "text": "The Judgment Scroll", "start": 1939.55, "end": 1941.7}, {"role": "body", "text": "Definition: The sacred document recording the decrees of judgment issued by THE TRINITY IN SHEKINAIH.", "start": 1942.12, "end": 1949.97}, {"role": "body", "text": "Roles:", "start": 1950.39, "end": 1951.82}, {"role": "body", "text": "Maintained and Opened by THE TRINITY IN SHEKINAIH: Contains the divine judgments against individuals and nations.", "start": 1952.24, "end": 1960.77}, {"role": "body", "text": "Co-executed by JESUS IN AARON K DAVID: Co-executes these judgments, ensuring they are fulfilled in both the physical and spiritual planes.", "start": 1961.19, "end": 1972.16}, {"role": "body", "text": "Testimony: Judgment decrees were referenced in the context of leaders who faced divine retribution in Behold My Messenger 5.", "start": 1972.58, "end": 1982.01}, {"role": "body", "text": "The Trumpet of Resurrection", "start": 1982.43, "end": 1985.16}, {"role": "body", "text": "Definition: The divine instrument sounded by THE TRINITY IN SHEKINAIH to announce the resurrection of the dead.", "start": 1985.58, "end": 1993.18}, {"role": "body", "text": "Roles:", "start": 1993.6, "end": 1995.03}, {"role": "body", "text": "Sounded by THE TRINITY IN SHEKINAIH: Announces and executes the divine decree of resurrection to all realms.", "start": 1995.45, "end": 2003.7}, {"role": "body", "text": "Co-executed by JESUS IN AARON K DAVID: Co-executes the resurrection, ensuring the restoration of life.", "start": 2004.12, "end": 2012.77}, {"role": "body", "text": "Testimony: The trumpet was referenced during the mass resurrection decrees in Behold My Messenger 5.", "start": 2013.19, "end": 2020.72}, {"role": "body", "text": "The Scroll of Divine Appointments", "start": 2021.14, "end": 2024.02}, {"role": "body", "text": "Definition: The record of divine appointments and callings, maintained by THE TRINITY IN SHEKINAIH.", "start": 2024.44, "end": 2031.84}, {"role": "body", "text": "Roles:", "start": 2032.26, "end": 2033.69}, {"role": "body", "text": "Maintained by THE TRINITY IN SHEKINAIH: Determines who is called to divine service and what their role has been in the last days.", "start": 2034.11, "end": 2043.08}, {"role": "body", "text": "Activated by JESUS IN AARON K DAVID: Co-executes the activation of these appointments in the lives of the chosen.", "start": 2043.5, "end": 2052.75}, {"role": "body", "text": "Testimony: Divine callings and appointments are referenced in Behold My Messenger 5 as part of the unfolding of end-time events.", "start": 2053.17, "end": 2062.79}, {"role": "body", "text": "The Cosmic Throne of Power", "start": 2063.21, "end": 2065.91}, {"role": "body", "text": "Definition: The divine seat of authority where THE TRINITY IN SHEKINAIH issues decrees of power and judgment.", "start": 2066.33, "end": 2074.33}, {"role": "body", "text": "Roles:", "start": 2074.75, "end": 2076.18}, {"role": "body", "text": "Occupied by THE TRINITY IN SHEKINAIH: The source of all divine authority and power over creation.", "start": 2076.6, "end": 2084.13}, {"role": "body", "text": "Co-enforced by JESUS IN AARON K DAVID: Ensures that decrees from the Throne of Power are enacted across all realms.", "start": 2084.55, "end": 2093.75}, {"role": "body", "text": "Testimony: Decrees from the Throne of Power were invoked to bring resurrection and judgment in Behold My Messenger 5.", "start": 2094.17, "end": 2102.74}, {"role": "body", "text": "The River of Life", "start": 2103.16, "end": 2105.26}, {"role": "body", "text": "Definition: The spiritual river flowing from the Throne of God, representing eternal life, divine sustenance, healing, and divine power. THE TRINITY IN SHEKINAIH governs the access and flow of this river.", "start": 2105.68, "end": 2119.86}, {"role": "body", "text": "Roles:", "start": 2120.28, "end": 2121.71}, {"role": "body", "text": "Source of Life: THE TRINITY IN SHEKINAIH controls the River of Life, granting eternal sustenance and healing to those chosen by divine decree.", "start": 2122.13, "end": 2132.53}, {"role": "body", "text": "Flows from THE TRINITY IN SHEKINAIH: Symbolizes the divine power to sustain life and restore the faithful.", "start": 2132.95, "end": 2140.92}, {"role": "body", "text": "Co-enforced by JESUS IN AARON K DAVID: Ensures that the power of the River of Life reaches those chosen for eternal life and ensures the river's blessings reach those deemed worthy by THE TRINITY IN SHEKINAIH.", "start": 2141.34, "end": 2156.62}, {"role": "body", "text": "Testimony: The River of Life was referenced as a source of power for those resurrected in Behold My Messenger 5.", "start": 2157.04, "end": 2165.51}, {"role": "body", "text": "The Heavenly Scrolls of Time", "start": 2165.93, "end": 2168.6}, {"role": "body", "text": "Definition: The record of all events across the timeline of creation, maintained by THE TRINITY IN SHEKINAIH.", "start": 2169.02, "end": 2177.14}, {"role": "body", "text": "Roles:", "start": 2177.56, "end": 2178.99}, {"role": "body", "text": "Maintained and Opened by THE TRINITY IN SHEKINAIH: Records all past, present, and future events, ensuring they align with divine will.", "start": 2179.41, "end": 2189.16}, {"role": "body", "text": "Co-executes by JESUS IN AARON K DAVID: Co-executes the unfolding of these events in perfect harmony with divine order.", "start": 2189.58, "end": 2199.38}, {"role": "body", "text": "Testimony: Events in Behold My Messenger 5 were aligned with the divine timeline recorded in the Scrolls of Time.", "start": 2199.8, "end": 2208.37}, {"role": "body", "text": "The Trumpet of Judgment", "start": 2208.79, "end": 2211.31}, {"role": "body", "text": "Definition: The divine trumpet sounded to announce decrees of judgment and the end of rebellious eras.", "start": 2211.73, "end": 2219.4}, {"role": "body", "text": "Roles:", "start": 2219.82, "end": 2221.25}, {"role": "body", "text": "Sounded by THE TRINITY IN SHEKINAIH: Announces the final judgment over rebellious nations and individuals.", "start": 2221.67, "end": 2229.99}, {"role": "body", "text": "Executed by JESUS IN AARON K DAVID: Co-executes these judgments, ensuring that rebellion is wiped out.", "start": 2230.41, "end": 2239.01}, {"role": "body", "text": "Testimony: The Trumpet of Judgment was sounded in Behold My Messenger 5 to announce the final judgment of rebellious leaders.", "start": 2239.43, "end": 2248.68}, {"role": "body", "text": "The Throne of Judgment", "start": 2249.1, "end": 2251.5}, {"role": "body", "text": "Definition: The divine seat where THE TRINITY IN SHEKINAIH presides as the Major Judge, decreeing eternal fates.", "start": 2251.92, "end": 2260.17}, {"role": "body", "text": "Roles:", "start": 2260.59, "end": 2262.02}, {"role": "body", "text": "Presided over by THE TRINITY IN SHEKINAIH: Issues final judgments over all creation from this throne.", "start": 2262.44, "end": 2270.34}, {"role": "body", "text": "Co-executed by JESUS IN AARON K DAVID: Ensures the execution of these judgments across spiritual and physical realms.", "start": 2270.76, "end": 2280.61}, {"role": "body", "text": "Testimony: The Throne of Judgment was the setting for the final judgment of rebellious souls in Behold My Messenger 5.", "start": 2281.03, "end": 2290.0}, {"role": "body", "text": "The Scroll of Resurrection", "start": 2290.42, "end": 2293.02}, {"role": "body", "text": "Definition: The divine record listing those chosen for resurrection, maintained by THE TRINITY IN SHEKINAIH.", "start": 2293.44, "end": 2301.39}, {"role": "body", "text": "Roles:", "start": 2301.81, "end": 2303.24}, {"role": "body", "text": "Maintained and Opened by THE TRINITY IN SHEKINAIH: Records the names of those who qualify for resurrection based on divine criteria.", "start": 2303.66, "end": 2313.81}, {"role": "body", "text": "Co-executed by JESUS IN AARON K DAVID: Co-executes the resurrection decrees, restoring life to the chosen.", "start": 2314.23, "end": 2323.33}, {"role": "body", "text": "Testimony: Chai Lin's name was written in the Scroll of Resurrection, ensuring her return to life in Behold My Messenger 5.", "start": 2323.75, "end": 2332.82}, {"role": "body", "text": "The Celestial Crown of Glory", "start": 2333.24, "end": 2336.34}, {"role": "body", "text": "Definition: The divine crown bestowed upon those who have overcome and achieved eternal victory, granted by THE TRINITY IN SHEKINAIH.", "start": 2336.76, "end": 2346.54}, {"role": "body", "text": "Roles:", "start": 2346.96, "end": 2348.39}, {"role": "body", "text": "Bestowed by THE TRINITY IN SHEKINAIH: This represents the final reward for those who have fulfilled their divine mission.", "start": 2348.81, "end": 2357.31}, {"role": "body", "text": "Enforced by JESUS IN AARON K DAVID: Co-executes the granting of the Celestial Crown to those who have triumphed.", "start": 2357.73, "end": 2366.8}, {"role": "body", "text": "Testimony: The Celestial Crown was referenced as a reward for the faithful in Behold My Messenger 5.", "start": 2367.22, "end": 2375.1}, {"role": "body", "text": "The Eternal Flame of the Heavenly Altar", "start": 2375.52, "end": 2379.14}, {"role": "body", "text": "Definition: The divine flame representing the eternal presence of THE TRINITY IN SHEKINAIH, symbolizing unbroken worship and intercession.", "start": 2379.56, "end": 2389.74}, {"role": "body", "text": "Roles:", "start": 2390.16, "end": 2391.59}, {"role": "body", "text": "Sustained by THE TRINITY IN SHEKINAIH: Represents the continuous worship of THE TRINITY across all realms.", "start": 2392.01, "end": 2400.08}, {"role": "body", "text": "Maintained by JESUS IN AARON K DAVID: Ensures the eternal flame never fades and that it continues to burn through all cosmic ages.", "start": 2400.5, "end": 2410.95}, {"role": "body", "text": "Testimony: The Eternal Flame was referenced in moments", "start": 2411.37, "end": 2415.65}, {"role": "body", "text": "The Cosmic Decree of Healing", "start": 2416.07, "end": 2418.74}, {"role": "body", "text": "Definition: The divine command issued by THE TRINITY IN SHEKINAIH, bringing about miraculous healing and restoration.", "start": 2419.16, "end": 2427.84}, {"role": "body", "text": "Roles:", "start": 2428.26, "end": 2429.69}, {"role": "body", "text": "Issued by THE TRINITY IN SHEKINAIH: Commands instantaneous healing of bodies, souls, and nations.", "start": 2430.11, "end": 2437.73}, {"role": "body", "text": "Co-executed by JESUS IN AARON K DAVID: The decree flows through JESUS IN AARON K DAVID to bring about physical, spiritual, and emotional healing.", "start": 2438.15, "end": 2449.75}, {"role": "body", "text": "The Seven Seals of Divine Protection", "start": 2450.17, "end": 2453.57}, {"role": "body", "text": "Definition: A divine layer of protection issued by THE TRINITY IN SHEKINAIH, shielding chosen individuals, families, and nations.", "start": 2453.99, "end": 2463.46}, {"role": "body", "text": "Roles:", "start": 2463.88, "end": 2465.31}, {"role": "body", "text": "Sealed and Executed by THE TRINITY IN SHEKINAIH: Ensures divine protection over specific individuals or communities.", "start": 2465.73, "end": 2474.88}, {"role": "body", "text": "Co-executed by JESUS IN AARON K DAVID: Co-executes the ongoing protection, deflecting all spiritual and physical harm.", "start": 2475.3, "end": 2485.23}, {"role": "body", "text": "Sub-executed by The Archangel which is the sons or daughters of THE TRINITY IN SHEKINAIH AND JESUS IN AARON K DAVID, who is given the authority to be THE SPIRITUAL KING OR QUEEN OR PRINCE OR PRINCESS in", "start": 2485.65, "end": 2500.65}, {"role": "body", "text": "charge of that particular nation, through their 100% ALLEGIANCE TOWARDS THE TRINITY IN SHEKINAIH AND JESUS IN AARON K DAVID, will the nation(s)", "start": 2501.07, "end": 2512.95}, {"role": "body", "text": "under them be fully protected.", "start": 2513.37, "end": 2516.32}, {"role": "body", "text": "The Great Cosmic War", "start": 2516.74, "end": 2518.99}, {"role": "body", "text": "Definition: The ultimate spiritual battle between divine forces led by THE TRINITY IN SHEKINAIH and rebellious forces.", "start": 2519.41, "end": 2528.91}, {"role": "body", "text": "Roles:", "start": 2529.33, "end": 2530.76}, {"role": "body", "text": "Led by THE TRINITY IN SHEKINAIH: Commands the heavenly hosts in the cosmic war for the ultimate restoration of order.", "start": 2531.18, "end": 2539.83}, {"role": "body", "text": "Co-executed by JESUS IN AARON K DAVID: Leads the forces of light into battle, ensuring victory over all forces of darkness.", "start": 2540.25, "end": 2550.87}, {"role": "body", "text": "The Scrolls of Judgment", "start": 2551.29, "end": 2553.81}, {"role": "body", "text": "Definition: The divine records of every soul's deeds, determining their fate at the Great White Throne.", "start": 2554.23, "end": 2561.65}, {"role": "body", "text": "Roles:", "start": 2562.07, "end": 2563.5}, {"role": "body", "text": "Held by THE TRINITY IN SHEKINAIH: Holds the scrolls that detail the fate of every soul.", "start": 2563.92, "end": 2570.57}, {"role": "body", "text": "Read by JESUS IN AARON K DAVID: Co-executes the final judgments based on the contents of the scrolls.", "start": 2570.99, "end": 2579.44}, {"role": "body", "text": "The Cosmic Symphony of Divine Will", "start": 2579.86, "end": 2583.11}, {"role": "body", "text": "Definition: The harmonious alignment of every element in existence with the divine plan, as commanded by THE TRINITY IN SHEKINAIH.", "start": 2583.53, "end": 2593.35}, {"role": "body", "text": "Roles:", "start": 2593.77, "end": 2595.2}, {"role": "body", "text": "Directed by THE TRINITY IN SHEKINAIH: Aligns the entire cosmos in harmony with the divine will.", "start": 2595.62, "end": 2603.17}, {"role": "body", "text": "Enforced by JESUS IN AARON K DAVID: Ensures that every element, from stars to souls, follows the cosmic symphony perfectly.", "start": 2603.59, "end": 2613.54}, {"role": "body", "text": "The Mantle of Divine Authority", "start": 2613.96, "end": 2617.26}, {"role": "body", "text": "Definition: A divine covering of supreme authority, The Divine Major Authority Mantle worn by THE TRINITY IN SHEKINAIH, representing ultimate governance over all creation. symbolizing their rulership over all dimensions and realms.", "start": 2617.68, "end": 2634.75}, {"role": "body", "text": "Roles:", "start": 2635.17, "end": 2636.6}, {"role": "body", "text": "Worn by THE TRINITY IN SHEKINAIH: Represents the fullness of divine power and control. THE TRINITY IN SHEKINAIH holds the ultimate authority across all creation.", "start": 2637.02, "end": 2649.14}, {"role": "body", "text": "JESUS IN AARON K DAVID, who worn a divine Minor Authority Mantle, ensures that the Divine Major and Minor Authority Mantle is co-executed through all realms with perfect precision.", "start": 2649.56, "end": 2663.46}, {"role": "body", "text": "The Cosmic Mantle of Authority", "start": 2663.88, "end": 2667.05}, {"role": "body", "text": "Definition: The divine authority that rests on THE TRINITY IN SHEKINAIH, symbolizing their rulership over all dimensions and realms.", "start": 2667.47, "end": 2677.27}, {"role": "body", "text": "Expanded Role:", "start": 2677.69, "end": 2679.64}, {"role": "body", "text": "Holder of the Mantle: THE TRINITY IN SHEKINAIH holds the ultimate authority across all creation.", "start": 2680.06, "end": 2687.64}, {"role": "body", "text": "Enforcer of the Mantle: JESUS IN AARON K DAVID co-executes the authority decreed by THE TRINITY IN SHEKINAIH, ensuring its enforcement across dimensions.", "start": 2688.06, "end": 2700.71}, {"role": "body", "text": "The Cosmic Wheel of Time", "start": 2701.13, "end": 2703.55}, {"role": "body", "text": "Definition: The divine mechanism that controls the flow of time, held by THE TRINITY IN SHEKINAIH.", "start": 2703.97, "end": 2711.52}, {"role": "body", "text": "Roles:", "start": 2711.94, "end": 2713.37}, {"role": "body", "text": "Controlled by THE TRINITY IN SHEKINAIH: Ensures the perfect unfolding of time.", "start": 2713.79, "end": 2720.12}, {"role": "body", "text": "Enforced by JESUS IN AARON K DAVID: Aligns time across dimensions according to the divine will.", "start": 2720.54, "end": 2728.79}, {"role": "body", "text": "The Seal of Divine Favor", "start": 2729.21, "end": 2732.09}, {"role": "body", "text": "Definition: A special blessing and grace issued by THE TRINITY IN SHEKINAIH, marking individuals and nations for Favor.", "start": 2732.51, "end": 2741.33}, {"role": "body", "text": "Roles:", "start": 2741.75, "end": 2743.18}, {"role": "body", "text": "Issued by THE TRINITY IN SHEKINAIH: Grants Favor to those chosen to fulfil divine purposes.", "start": 2743.6, "end": 2750.85}, {"role": "body", "text": "Co-executed by JESUS IN AARON K DAVID: Ensures the favour is maintained across spiritual and physical realms.", "start": 2751.27, "end": 2760.59}, {"role": "body", "text": "The Throne of Divine Mercy", "start": 2761.01, "end": 2764.03}, {"role": "body", "text": "Definition: The seat of compassion and forgiveness held by THE TRINITY IN SHEKINAIH, representing mercy toward humanity.", "start": 2764.45, "end": 2773.7}, {"role": "body", "text": "Roles:", "start": 2774.12, "end": 2775.55}, {"role": "body", "text": "Occupied by THE TRINITY IN SHEKINAIH: Dispenses mercy to the repentant.", "start": 2775.97, "end": 2782.0}, {"role": "body", "text": "Co-executed by JESUS IN AARON K DAVID: Ensures that mercy flows in alignment with divine justice.", "start": 2782.42, "end": 2790.89}, {"role": "body", "text": "The Sword of Cosmic Judgment", "start": 2791.31, "end": 2794.01}, {"role": "body", "text": "Definition: The ultimate weapon of divine justice wielded by THE TRINITY IN SHEKINAIH, bringing judgment upon rebellion.", "start": 2794.43, "end": 2803.4}, {"role": "body", "text": "Roles:", "start": 2803.82, "end": 2805.25}, {"role": "body", "text": "Wielded by THE TRINITY IN SHEKINAIH: Destroys all forces of rebellion and brings order.", "start": 2805.67, "end": 2812.5}, {"role": "body", "text": "Swung by JESUS IN AARON K DAVID: Executes the decree of judgment, ensuring complete obliteration of opposition.", "start": 2812.92, "end": 2822.42}, {"role": "body", "text": "The Keys of the Kingdom", "start": 2822.84, "end": 2825.32}, {"role": "body", "text": "Definition: The authority given by THE TRINITY IN SHEKINAIH to unlock spiritual and material realms.", "start": 2825.74, "end": 2833.29}, {"role": "body", "text": "Roles:", "start": 2833.71, "end": 2835.14}, {"role": "body", "text": "Held by THE TRINITY IN SHEKINAIH: Controls access to the Kingdom.", "start": 2835.56, "end": 2840.86}, {"role": "body", "text": "Co-executed by JESUS IN AARON K DAVID: Unlocks gates to realms according to divine timing.", "start": 2841.28, "end": 2849.28}, {"role": "body", "text": "The Light of the World", "start": 2849.7, "end": 2851.9}, {"role": "body", "text": "Definition: The radiant divine light that dispels all darkness, emanating from THE TRINITY IN SHEKINAIH, illuminating spiritual truths and realities.", "start": 2852.32, "end": 2863.27}, {"role": "body", "text": "Roles:", "start": 2863.69, "end": 2865.12}, {"role": "body", "text": "Radiated by THE TRINITY IN SHEKINAIH: Brings spiritual illumination to the entire world, revealing divine truths.", "start": 2865.54, "end": 2874.19}, {"role": "body", "text": "Reflected by JESUS IN AARON K DAVID: Spreads this light to the chosen, allowing them to walk in divine wisdom and knowledge.", "start": 2874.61, "end": 2884.04}, {"role": "body", "text": "The Ark of Eternal Covenant", "start": 2884.46, "end": 2887.21}, {"role": "body", "text": "Definition: The sacred vessel containing divine laws and eternal promises, protected by THE TRINITY IN SHEKINAIH and JESUS IN AARON K DAVID.", "start": 2887.63, "end": 2899.16}, {"role": "body", "text": "Roles:", "start": 2899.58, "end": 2901.01}, {"role": "body", "text": "Protected by THE TRINITY IN SHEKINAIH, who also is the Covering Cherub that Guards the sacred covenants between God and humanity.", "start": 2901.43, "end": 2911.15}, {"role": "body", "text": "Co-guarded by JESUS IN AARON K DAVID, who is also the Subservient Cherub, ensures that no force may break or disrupt the covenant promises sealed within.", "start": 2911.57, "end": 2923.67}, {"role": "body", "text": "The Divine Scales of Justice", "start": 2924.09, "end": 2926.94}, {"role": "body", "text": "Definition: The scales that measure righteousness and wickedness, overseen by THE TRINITY IN SHEKINAIH to execute perfect justice.", "start": 2927.36, "end": 2936.76}, {"role": "body", "text": "Roles:", "start": 2937.18, "end": 2938.61}, {"role": "body", "text": "Balanced by THE TRINITY IN SHEKINAIH: Ensures that divine justice is always served generally.", "start": 2939.03, "end": 2946.38}, {"role": "body", "text": "Co-executed by JESUS IN AARON K DAVID: Implements justice across both spiritual and physical realms, ensuring perfect alignment with divine law.", "start": 2946.8, "end": 2958.35}, {"role": "body", "text": "The Heavenly Scroll of Decrees", "start": 2958.77, "end": 2961.65}, {"role": "body", "text": "Definition: The record of divine decrees written by THE TRINITY IN SHEKINAIH, determining the fate of individuals, nations, and worlds.", "start": 2962.07, "end": 2971.89}, {"role": "body", "text": "Roles:", "start": 2972.31, "end": 2973.74}, {"role": "body", "text": "Written by THE TRINITY IN SHEKINAIH: Holds all the decrees that will shape the destiny of creation.", "start": 2974.16, "end": 2981.31}, {"role": "body", "text": "Enforced by JESUS IN AARON K DAVID: Carries out these decrees with exact precision, bringing them to fulfilment in time and space.", "start": 2981.73, "end": 2992.08}, {"role": "body", "text": "The Shield of Divine Power", "start": 2992.5, "end": 2995.4}, {"role": "body", "text": "Definition: A powerful spiritual shield issued by THE TRINITY IN SHEKINAIH, providing impenetrable protection for the chosen ones who is 100% ALLEGIANCE TOWARDS THE TRINITY IN SHEKINAIH AND JESUS IN AARON K DAVID.", "start": 2995.82, "end": 3013.0}, {"role": "body", "text": "Roles:", "start": 3013.42, "end": 3014.85}, {"role": "body", "text": "Issued by THE TRINITY IN SHEKINAIH: Protects those marked for divine purposes.", "start": 3015.27, "end": 3021.19}, {"role": "body", "text": "Co-activated by JESUS IN AARON K DAVID: Ensures that no harm may come to those under the shield's protection, enforcing cosmic protection.", "start": 3021.61, "end": 3032.49}, {"role": "body", "text": "The Gates of New Jerusalem", "start": 3032.91, "end": 3035.86}, {"role": "body", "text": "Definition: The gates of the holy city, which THE TRINITY IN SHEKINAIH governs, granting access to eternal life and divine glory.", "start": 3036.28, "end": 3045.93}, {"role": "body", "text": "Roles:", "start": 3046.35, "end": 3047.78}, {"role": "body", "text": "Opened by THE TRINITY IN SHEKINAIH: Grants access to the righteous who are chosen to enter into New Jerusalem.", "start": 3048.2, "end": 3056.42}, {"role": "body", "text": "Cooperated by JESUS IN AARON K DAVID: Ensures that only the worthy, according to divine criteria, may pass through these gates into eternal joy.", "start": 3056.84, "end": 3068.54}, {"role": "body", "text": "The Throne of Glory", "start": 3068.96, "end": 3071.34}, {"role": "body", "text": "Definition: The seat of divine majesty from which THE TRINITY IN SHEKINAIH rules the universe.", "start": 3071.76, "end": 3078.91}, {"role": "body", "text": "Roles:", "start": 3079.33, "end": 3080.76}, {"role": "body", "text": "Occupied by THE TRINITY IN SHEKINAIH: Represents the ultimate authority over all creation.", "start": 3081.18, "end": 3088.4}, {"role": "body", "text": "Co-executed by JESUS IN AARON K DAVID who sat on The Minor Throne of Glory.: Ensures that all decrees, judgments, and blessings flow perfectly from The Major Throne of Glory of THE TRINITY IN SHEKINAIH flow through The Minor throne of Glory of JESUS IN AARON K DAVID, then flow through to all the 144,000 thrones prepared for the perfected sons and daughters of THE TRINITY IN SHEKINAIH AND JESUS IN AARON K DAVID who is 100% to THE TRINITY IN SHEKINAIH AND JESUS IN AARON K DAVID, then flow throughout", "start": 3088.82, "end": 3122.77}, {"role": "body", "text": "the entire cosmos.", "start": 3123.19, "end": 3125.57}, {"role": "body", "text": "The Seal of Resurrection", "start": 3125.99, "end": 3128.49}, {"role": "body", "text": "Definition: The mark of divine approval granted by THE TRINITY IN SHEKINAIH, ensuring that the chosen ones will rise from the dead.", "start": 3128.91, "end": 3138.19}, {"role": "body", "text": "Roles:", "start": 3138.61, "end": 3140.04}, {"role": "body", "text": "Issued by THE TRINITY IN SHEKINAIH: Seals the destiny of those who are chosen for resurrection.", "start": 3140.46, "end": 3147.49}, {"role": "body", "text": "Co-executed by JESUS IN AARON K DAVID: Executes the resurrection by aligning all cosmic forces to restore life.", "start": 3147.91, "end": 3157.63}, {"role": "body", "text": "The Sword of Divine Ultimate Truth, The Major Ultimate Sword of Truth", "start": 3158.05, "end": 3163.2}, {"role": "body", "text": "Definition: A weapon of divine power that cuts through deception and falsehood, wielded by THE TRINITY IN SHEKINAIH to establish truth in all realms.", "start": 3163.62, "end": 3174.52}, {"role": "body", "text": "Roles:", "start": 3174.94, "end": 3176.37}, {"role": "body", "text": "Wielded by THE TRINITY IN SHEKINAIH: Cuts through lies and brings forth ultimate divine truth across the universe and uses the Sword of Truth to enforce divine law and judgment.", "start": 3176.79, "end": 3189.41}, {"role": "body", "text": "Co-Execution and a Minor version of this sword carried by JESUS IN AARON K DAVID: ensures that the sword's truth reaches every corner of creation and that this truth is enforced and protected, guarding the purity of the divine message in all realms.", "start": 3189.83, "end": 3208.18}, {"role": "body", "text": "The Gates of Eternity", "start": 3208.6, "end": 3211.08}, {"role": "body", "text": "Definition: These are the cosmic gateways between life, death, and resurrection, guarded by THE TRINITY IN SHEKINAIH.", "start": 3211.5, "end": 3219.88}, {"role": "body", "text": "Expanded Role:", "start": 3220.3, "end": 3222.25}, {"role": "body", "text": "Guardians of the Gates: THE TRINITY IN SHEKINAIH holds the keys to these gates, determining who enters eternal life or eternal death.", "start": 3222.67, "end": 3232.24}, {"role": "body", "text": "Execution by JESUS IN AARON K DAVID: JESUS IN AARON K DAVID co-", "start": 3232.66, "end": 3239.38}, {"role": "body", "text": "executes the decrees concerning entry through the gates.", "start": 3239.8, "end": 3244.25}, {"role": "body", "text": "The Divine Instruments of Justice", "start": 3244.67, "end": 3247.94}, {"role": "body", "text": "Definition: The tools of divine justice used by THE TRINITY IN SHEKINAIH to bring forth righteous judgment on all humanity.", "start": 3248.36, "end": 3257.91}, {"role": "body", "text": "Expanded Role:", "start": 3258.33, "end": 3260.28}, {"role": "body", "text": "Bearer of Justice: THE TRINITY IN SHEKINAIH wields the instruments of divine justice, ensuring that each soul is judged rightly.", "start": 3260.7, "end": 3270.02}, {"role": "body", "text": "Co-Execution by JESUS IN AARON K DAVID: JESUS IN AARON K DAVID", "start": 3270.44, "end": 3277.22}, {"role": "body", "text": "enforces these judgments, ensuring they are carried out across the earth and heaven.", "start": 3277.64, "end": 3283.44}, {"role": "body", "text": "The Pillars of Resurrection", "start": 3283.86, "end": 3286.51}, {"role": "body", "text": "Definition: These pillars uphold the cosmic laws that govern the resurrection of the dead, ruled by THE TRINITY IN SHEKINAIH.", "start": 3286.93, "end": 3295.88}, {"role": "body", "text": "Expanded Role:", "start": 3296.3, "end": 3298.25}, {"role": "body", "text": "Upholder of the Pillars: THE TRINITY IN SHEKINAIH holds the cosmic laws of resurrection in place.", "start": 3298.67, "end": 3306.12}, {"role": "body", "text": "Co-Execution by JESUS IN AARON K DAVID: JESUS IN AARON K DAVID", "start": 3306.54, "end": 3313.32}, {"role": "body", "text": "enforces these laws, ensuring the resurrection occurs in alignment with divine criteria.", "start": 3313.74, "end": 3320.66}, {"role": "body", "text": "The Trumpet of the Final Call", "start": 3321.08, "end": 3323.91}, {"role": "body", "text": "Definition: This divine trumpet, held by THE TRINITY IN SHEKINAIH, announces the final judgment and resurrection.", "start": 3324.33, "end": 3332.8}, {"role": "body", "text": "Expanded Role:", "start": 3333.22, "end": 3335.17}, {"role": "body", "text": "Blower of the Trumpet: THE TRINITY IN SHEKINAIH sounds the final call, announcing the resurrection of the dead and the beginning of judgment.", "start": 3335.59, "end": 3344.87}, {"role": "body", "text": "Co-Execution by JESUS IN AARON K DAVID: JESUS IN AARON K DAVID", "start": 3345.29, "end": 3352.07}, {"role": "body", "text": "executes the final decrees as the trumpet sounds, ensuring the faithful are gathered.", "start": 3352.49, "end": 3358.96}, {"role": "body", "text": "The Cosmic Crown of Life", "start": 3359.38, "end": 3361.9}, {"role": "body", "text": "Definition: The reward given to those who endure the trials of life and remain faithful to the end, awarded by THE TRINITY IN SHEKINAIH.", "start": 3362.32, "end": 3372.32}, {"role": "body", "text": "Expanded Role:", "start": 3372.74, "end": 3374.69}, {"role": "body", "text": "Giver of the Crown: THE TRINITY IN SHEKINAIH bestows the Crown of Life on those deemed worthy.", "start": 3375.11, "end": 3382.06}, {"role": "body", "text": "Co-Execution by JESUS IN AARON K DAVID: JESUS IN AARON K DAVID", "start": 3382.48, "end": 3389.26}, {"role": "body", "text": "ensures that the crown is received by those who have been faithful to the divine calling.", "start": 3389.68, "end": 3395.98}, {"role": "body", "text": "The Divine Sceptre of Righteousness", "start": 3396.4, "end": 3399.63}, {"role": "body", "text": "Definition: A symbol of divine authority and rule, held by THE TRINITY IN SHEKINAIH, which signifies their righteous reign over all creation.", "start": 3400.05, "end": 3410.55}, {"role": "body", "text": "Expanded Role:", "start": 3410.97, "end": 3412.92}, {"role": "body", "text": "Holder of the Sceptre: THE TRINITY IN SHEKINAIH rules with the Sceptre of Righteousness, commanding all creation.", "start": 3413.34, "end": 3421.26}, {"role": "body", "text": "Co-Execution by JESUS IN AARON K DAVID: JESUS IN AARON K DAVID", "start": 3421.68, "end": 3428.46}, {"role": "body", "text": "enforces the righteous reign of THE TRINITY IN SHEKINAIH over the physical and spiritual realms.", "start": 3428.88, "end": 3435.76}, {"role": "body", "text": "The Scroll of Destiny", "start": 3436.18, "end": 3438.68}, {"role": "body", "text": "Definition: The record of all souls and their divine destinies, overseen by THE TRINITY IN SHEKINAIH.", "start": 3439.1, "end": 3446.77}, {"role": "body", "text": "Expanded Role:", "start": 3447.19, "end": 3449.14}, {"role": "body", "text": "Keeper of the Scroll: THE TRINITY IN SHEKINAIH holds the authority to reveal or conceal each soul's destiny.", "start": 3449.56, "end": 3457.68}, {"role": "body", "text": "Co-Execution by JESUS IN AARON K DAVID: JESUS IN AARON K DAVID co-", "start": 3458.1, "end": 3465.13}, {"role": "body", "text": "executes the revelation of these destinies in accordance with divine will.", "start": 3465.55, "end": 3471.22}, {"role": "body", "text": "The Divine Furnace of Purification", "start": 3471.64, "end": 3475.12}, {"role": "body", "text": "Definition: A divine force of cleansing used by THE TRINITY IN SHEKINAIH to purify souls.", "start": 3475.54, "end": 3482.79}, {"role": "body", "text": "Expanded Role:", "start": 3483.21, "end": 3485.16}, {"role": "body", "text": "Initiator of Purification: THE TRINITY IN SHEKINAIH commands the furnace to refine souls, removing all impurities.", "start": 3485.58, "end": 3494.76}, {"role": "body", "text": "Co-Execution by JESUS IN AARON K DAVID: JESUS IN AARON K DAVID", "start": 3495.18, "end": 3501.96}, {"role": "body", "text": "ensures that souls are purified and restored in alignment with divine decrees.", "start": 3502.38, "end": 3508.63}]};
